import{_ as d,o as e,c as o,ag as r}from"./chunks/framework.HG0H2VLS.js";const u=JSON.parse('{"title":"Theme Colours","description":"","frontmatter":{},"headers":[],"relativePath":"tokens/theme-colours.md","filePath":"tokens/theme-colours.md"}'),a={name:"tokens/theme-colours.md"};function c(s,t,n,i,h,l){return e(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="theme-colours" tabindex="-1">Theme Colours <a class="header-anchor" href="#theme-colours" aria-label="Permalink to &quot;Theme Colours&quot;">​</a></h1><p>Semantic colour tokens that adapt across four modes: <strong>Light</strong>, <strong>Dark</strong>, <strong>Chat Light</strong>, and <strong>Chat Dark</strong>. These are the tokens used in component CSS.</p><h2 id="how-modes-work" tabindex="-1">How modes work <a class="header-anchor" href="#how-modes-work" aria-label="Permalink to &quot;How modes work&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mode</th><th>Activation</th><th>CSS file</th></tr></thead><tbody><tr><td>Light</td><td>Default (<code>:root</code>)</td><td><code>tokens.css</code></td></tr><tr><td>Dark</td><td><code>data-theme=&quot;dark&quot;</code> on <code>&lt;html&gt;</code></td><td><code>tokens-dark.css</code></td></tr><tr><td>Chat Light</td><td><code>data-surface=&quot;chat&quot;</code> on a container</td><td><code>tokens-chat.css</code></td></tr><tr><td>Chat Dark</td><td>Both attributes present</td><td><code>tokens-chat-dark.css</code></td></tr></tbody></table><p>Chat modes use a <strong>pure neutral palette</strong> (no blue undertone) distinct from the core semantic palette. Components use the same token names — the mode selector handles the value switch.</p><h2 id="surface-tokens" tabindex="-1">Surface tokens <a class="header-anchor" href="#surface-tokens" aria-label="Permalink to &quot;Surface tokens&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Token</th><th>Light</th><th>Dark</th><th>Chat Light</th><th>Chat Dark</th></tr></thead><tbody><tr><td><code>--ai-surface-primary</code></td><td><code>#FFFFFF</code></td><td><code>#1B1B1F</code></td><td><code>#FFFFFF</code></td><td><code>#212123</code></td></tr><tr><td><code>--ai-surface-elevated-1</code></td><td><code>#FFFFFF</code></td><td><code>#212123</code></td><td><code>#FFFFFF</code></td><td><code>#2E2E32</code></td></tr><tr><td><code>--ai-surface-elevated-2</code></td><td><code>#FFFFFF</code></td><td><code>#2E2E32</code></td><td><code>#FFFFFF</code></td><td><code>#3C3C3F</code></td></tr><tr><td><code>--ai-surface-minimal</code></td><td><code>#F6F6F7</code></td><td><code>#212123</code></td><td><code>#E2E2E3</code></td><td><code>#2E2E32</code></td></tr><tr><td><code>--ai-surface-secondary</code></td><td><code>#E2E2E3</code></td><td><code>#2E2E32</code></td><td><code>#FFFFFF</code></td><td><code>#2E2E32</code></td></tr><tr><td><code>--ai-surface-contrast</code></td><td><code>#C2C2C4</code></td><td><code>#3C3C3F</code></td><td><code>#F6F6F7</code></td><td><code>#1B1B1F</code></td></tr><tr><td><code>--ai-surface-invert</code></td><td><code>#1B1B1F</code></td><td><code>#F6F6F7</code></td><td><code>#1B1B1F</code></td><td><code>#F6F6F7</code></td></tr></tbody></table><h3 id="elevation" tabindex="-1">Elevation <a class="header-anchor" href="#elevation" aria-label="Permalink to &quot;Elevation&quot;">​</a></h3><p>Elevation tokens convey depth — surfaces that float above other surfaces.</p><ul><li><strong>Light mode:</strong> All elevated surfaces are white (shadows handle depth)</li><li><strong>Dark mode:</strong> Elevated surfaces step up the neutral palette (shadows alone are invisible on dark)</li></ul><table tabindex="0"><thead><tr><th>Level</th><th>Use</th><th>Light</th><th>Dark</th></tr></thead><tbody><tr><td>Base (<code>surface-primary</code>)</td><td>Page background</td><td><code>#FFFFFF</code></td><td><code>#1B1B1F</code></td></tr><tr><td><code>surface-elevated-1</code></td><td>Cards, dropdowns, modals (StyleSettings, SystemRole)</td><td><code>#FFFFFF</code></td><td><code>#212123</code></td></tr><tr><td><code>surface-elevated-2</code></td><td>Content on elevated surfaces (VersionHistoryRow Live)</td><td><code>#FFFFFF</code></td><td><code>#2E2E32</code></td></tr></tbody></table><h3 id="brand-surfaces" tabindex="-1">Brand surfaces <a class="header-anchor" href="#brand-surfaces" aria-label="Permalink to &quot;Brand surfaces&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Token</th><th>Value</th><th>Use</th></tr></thead><tbody><tr><td><code>--ai-surface-brand</code></td><td><code>#0071D8</code></td><td>Primary action backgrounds</td></tr><tr><td><code>--ai-surface-brand-light</code></td><td><code>#3A8FFF</code></td><td>Hover state on brand</td></tr><tr><td><code>--ai-surface-brand-dark</code></td><td><code>#0054A3</code></td><td>Pressed state on brand</td></tr><tr><td><code>--ai-surface-brand-contrast</code></td><td><code>#BFD1FF</code></td><td>Light brand tint</td></tr><tr><td><code>--ai-surface-brand-contrast-extra</code></td><td><code>#F0F3FF</code></td><td>Very light brand tint</td></tr></tbody></table><h2 id="text-tokens" tabindex="-1">Text tokens <a class="header-anchor" href="#text-tokens" aria-label="Permalink to &quot;Text tokens&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Token</th><th>Light</th><th>Dark</th><th>Use</th></tr></thead><tbody><tr><td><code>--ai-text-primary</code></td><td><code>#212123</code></td><td><code>#F6F6F7</code></td><td>Body text, headings</td></tr><tr><td><code>--ai-text-secondary</code></td><td><code>#3C3C3F</code></td><td><code>#E2E2E3</code></td><td>Supporting text</td></tr><tr><td><code>--ai-text-contrast</code></td><td><code>#67676C</code></td><td><code>#929295</code></td><td>Placeholder, captions</td></tr><tr><td><code>--ai-text-invert</code></td><td><code>#FFFFFF</code></td><td><code>#1B1B1F</code></td><td>Text on dark/brand backgrounds</td></tr><tr><td><code>--ai-text-error</code></td><td><code>#EF4444</code></td><td><code>#EF4444</code></td><td>Error messages</td></tr></tbody></table><h2 id="border-tokens" tabindex="-1">Border tokens <a class="header-anchor" href="#border-tokens" aria-label="Permalink to &quot;Border tokens&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Token</th><th>Light</th><th>Dark</th><th>Use</th></tr></thead><tbody><tr><td><code>--ai-border-primary</code></td><td><code>#1B1B1F</code></td><td><code>#F6F6F7</code></td><td>Strong dividers</td></tr><tr><td><code>--ai-border-secondary</code></td><td><code>#E2E2E3</code></td><td><code>#2E2E32</code></td><td>Default input/card borders</td></tr><tr><td><code>--ai-border-contrast</code></td><td><code>#C2C2C4</code></td><td><code>#3C3C3F</code></td><td>Subtle borders</td></tr><tr><td><code>--ai-border-invert</code></td><td><code>#1B1B1F</code></td><td><code>#F6F6F7</code></td><td>Active/selected state borders</td></tr><tr><td><code>--ai-border-brand</code></td><td><code>#0071D8</code></td><td><code>#0071D8</code></td><td>Brand-coloured borders</td></tr><tr><td><code>--ai-border-error</code></td><td><code>#EF4444</code></td><td><code>#EF4444</code></td><td>Error state borders</td></tr></tbody></table><h2 id="icon-tokens" tabindex="-1">Icon tokens <a class="header-anchor" href="#icon-tokens" aria-label="Permalink to &quot;Icon tokens&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Token</th><th>Light</th><th>Dark</th><th>Use</th></tr></thead><tbody><tr><td><code>--ai-icon-primary</code></td><td><code>#212123</code></td><td><code>#F6F6F7</code></td><td>Default icon colour</td></tr><tr><td><code>--ai-icon-secondary</code></td><td><code>#67676C</code></td><td><code>#929295</code></td><td>Secondary icon</td></tr><tr><td><code>--ai-icon-contrast</code></td><td><code>#929295</code></td><td><code>#929295</code></td><td>Muted/disabled icon</td></tr><tr><td><code>--ai-icon-invert</code></td><td><code>#FFFFFF</code></td><td><code>#1B1B1F</code></td><td>Icon on dark background</td></tr><tr><td><code>--ai-icon-brand</code></td><td><code>#0071D8</code></td><td><code>#0071D8</code></td><td>Brand-coloured icon</td></tr></tbody></table><h2 id="figma-source" tabindex="-1">Figma source <a class="header-anchor" href="#figma-source" aria-label="Permalink to &quot;Figma source&quot;">​</a></h2><ul><li><strong>Light + Dark modes:</strong> Design System library → Semantic collection</li><li><strong>Chat Light + Chat Dark modes:</strong> AI Chat file → Semantic collection (local variables aliasing published Primitives)</li></ul>',21)])])}const b=d(a,[["render",c]]);export{u as __pageData,b as default};
